## PHASE 2 — Import Excel Modal (FE)

### 2.1 Create `src/components/sat-hach/ImportResultsModal.tsx`

```tsx
"use client";

import React, { useState, useRef } from 'react';
import { X, Upload, Loader2, FileSpreadsheet, CheckCircle2, AlertCircle } from 'lucide-react';
import { toast } from 'sonner';
import { importExamResults } from '@/src/services/examService';

interface ImportResultsModalProps {
  isOpen: boolean;
  onClose: () => void;
  batchId: string;
  batchName: string;
  onSuccess: () => void;
}

export default function ImportResultsModal({ isOpen, onClose, batchId, batchName, onSuccess }: ImportResultsModalProps) {
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleFileChange = (f: File) => {
    const ext = f.name.split('.').pop()?.toLowerCase();
    if (!['xlsx', 'xls', 'csv'].includes(ext || '')) {
      toast.error('Chỉ chấp nhận file .xlsx, .xls, .csv');
      return;
    }
    setFile(f);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const f = e.dataTransfer.files[0];
    if (f) handleFileChange(f);
  };

  const handleImport = async () => {
    if (!file) {
      toast.error('Vui lòng chọn file Excel');
      return;
    }
    try {
      setIsUploading(true);
      const res = await importExamResults(batchId, file);
      if (res.status === 'success') {
        toast.success(`Import thành công! Đã cập nhật ${res.data?.imported || 0} kết quả.`);
        setFile(null);
        onSuccess();
      } else {
        toast.error(res.message || 'Import thất bại');
      }
    } catch (err: any) {
      toast.error(err.message || 'Lỗi khi import file');
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-[2rem] w-full max-w-lg shadow-2xl animate-in zoom-in-95 duration-200 overflow-hidden border border-gray-100">

        <div className="px-8 py-6 border-b border-gray-100 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-black text-gray-900 tracking-tight">Import kết quả thi</h2>
            <p className="text-sm font-medium text-gray-400 mt-0.5">Đợt: <span className="text-indigo-600">{batchName}</span></p>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-gray-900 hover:bg-gray-100 rounded-xl transition-all">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-8 flex flex-col gap-5">
          <div
            onDragOver={e => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleDrop}
            onClick={() => fileInputRef.current?.click()}
            className={`border-2 border-dashed rounded-3xl p-8 flex flex-col items-center gap-3 cursor-pointer transition-all ${
              isDragging ? 'border-indigo-400 bg-indigo-50' : 'border-gray-200 hover:border-indigo-300 hover:bg-gray-50'
            }`}
          >
            <input ref={fileInputRef} type="file" accept=".xlsx,.xls,.csv" className="hidden" onChange={e => e.target.files?.[0] && handleFileChange(e.target.files[0])} />
            {file ? (
              <>
                <CheckCircle2 className="w-10 h-10 text-emerald-500" />
                <div className="text-center">
                  <p className="font-extrabold text-gray-700">{file.name}</p>
                  <p className="text-xs text-gray-400 mt-1">{(file.size / 1024).toFixed(1)} KB</p>
                </div>
              </>
            ) : (
              <>
                <FileSpreadsheet className="w-10 h-10 text-gray-300" />
                <div className="text-center">
                  <p className="font-bold text-gray-500">Kéo thả file Excel vào đây</p>
                  <p className="text-xs text-gray-400 mt-1">hoặc click để chọn file (.xlsx, .xls, .csv)</p>
                </div>
              </>
            )}
          </div>

          <div className="p-4 bg-amber-50 border border-amber-100 rounded-2xl">
            <p className="text-xs font-bold text-amber-700 mb-2">📋 Cột bắt buộc:</p>
            <p className="text-[11px] text-amber-600 font-medium">student_id, name, result</p>
            <p className="text-[11px] text-amber-600 font-medium mt-1">Cột tùy chọn: theory_result, simulation_result, parking_result, road_result, note</p>
            <p className="text-[11px] text-amber-600 font-medium mt-1">Giá trị: pass | fail | absent | no_result</p>
          </div>
        </div>

        <div className="px-8 py-6 border-t border-gray-100 bg-gray-50/50 flex items-center justify-end gap-3">
          <button onClick={onClose} className="px-6 py-3 text-sm font-black text-gray-500 hover:text-gray-900 transition-colors uppercase tracking-widest text-[11px]">
            Hủy
          </button>
          <button
            onClick={handleImport}
            disabled={!file || isUploading}
            className="flex items-center gap-2 px-8 py-3.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-600/20 transition-all hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-widest text-[11px]"
          >
            {isUploading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Upload className="w-4 h-4" />}
            Import
          </button>
        </div>
      </div>
    </div>
  );
}
```

### 2.2 Update `src/services/examService.ts`
