const handleSaveResult = async (saveData: { 
  result: string; 
  theory_result?: string; 
  simulation_result?: string; 
  parking_result?: string; 
  road_result?: string; 
  note: string 
}) => {
  const { result, theory_result, simulation_result, parking_result, road_result, note } = saveData;
  if (!targetBatchForResults || !targetStudentForResults) return;

  try {
    const res = await getBatchById(targetBatchForResults._id);
    if (!res.success) throw new Error('Cập nhật thất bại');

    const batch = res.data;
    const updatedResults = (batch.studentResults || []).map((s: any) => {
      if (s.student_id === targetStudentForResults.id) {
        return { ...s, result, theory_result, simulation_result, parking_result, road_result, note };
      }
      return s;
    });

    await updateExamBatch(batch._id || batch.id, { studentResults: updatedResults });

    toast.success(`Đã cập nhật kết quả cho ${targetStudentForResults.name}`);
    fetchExams();
  } catch (err: any) {
    toast.error(err.message || 'Lỗi khi lưu kết quả');
  }
};
```

