/* ─── page ───────────────────────────────────────────── */
export default function SatHachPage() {
  const { user } = useAuth();
  const [activeTab, setActiveTab]       = useState<'exams' | 'no-schedule'>('exams');
  const [expandedId, setExpandedId]     = useState<string | null>(null);
  const [modalOpen, setModalOpen]       = useState(false);
  const [editData, setEditData]         = useState<ExamData | null>(null);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [assignStudent, setAssignStudent]     = useState<any>(null);

  const [exams, setExams] = useState<any[]>([]);
  const [studentsWithoutSchedule, setStudentsWithoutSchedule] = useState<any[]>([]);
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [batchToDelete, setBatchToDelete] = useState<{ id: string, name: string } | null>(null);
  const [loading, setLoading] = useState(true);
  const [studentsLoading, setStudentsLoading] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [licenseCategories, setLicenseCategories] = useState<any[]>([]);

  // Pagination for Students
  const [studentsPage, setStudentsPage] = useState(1);
  const [studentsTotal, setStudentsTotal] = useState(0);
  const STUDENT_LIMIT = 20;

  // Mapper helper
  const mapStudentForDrawer = (s: any) => {
    if (!s) return null;
    // Case 1: Simple object from exam.studentResults
    if (!s.user_id && s.name) {
      return {
        id: s.student_id || s._id || s.id,
        name: s.name,
        phone: '—', rank: '—', region: '—', status: '—'
      };
    }
    // Case 2: Full student object from studentsWithoutSchedule
    return {
      id: s._id || s.id,
      name: `${s.user_id?.last_name || ''} ${s.user_id?.first_name || ''}`.trim() || 'Học viên',
      phone: s.user_id?.phone || '—',
      rank: s.course_id?.level || '—',
      region: s.region?.name || s.region || '—',
      status: s.status_detail || s.status || '—'
    };
  };

  // Result Modal State
  const [resultModalOpen, setResultModalOpen] = useState(false);
  const [targetStudentForResults, setTargetStudentForResults] = useState<any>(null);
  const [targetBatchForResults, setTargetBatchForResults] = useState<any>(null);

  // Removal Confirmation
  const [removeConfirmOpen, setRemoveConfirmOpen] = useState(false);
  const [studentToRemove, setStudentToRemove] = useState<{ id: string, name: string, batchId: string } | null>(null);

  // filters
  const [fromDate, setFromDate]         = useState('');
  const [toDate, setToDate]             = useState('');
  const [filterVehicle, setFilterVehicle] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [search, setSearch]             = useState('');

  const fetchExams = async () => {
    try {
      setLoading(true);
      const res = await getExamBatches(1, 50);
      if (res.success) {
        // Handle standardized API envelope { data: { data: [] } } or { data: [] }
        const list = res.data?.data || res.data?.docs || (Array.isArray(res.data) ? res.data : []);
        setExams(list);
      }
    } catch (error) {
      toast.error('Không thể tải danh sách đợt thi');
    } finally {
      setLoading(false);
    }
  };
  const fetchEligibleStudents = async (page = 1) => {
    try {
      setStudentsLoading(true);
      const res = await getEligibleStudents(page, STUDENT_LIMIT);
      if (res.success) {
        const list = res.data?.data || res.data?.docs || (Array.isArray(res.data) ? res.data : []);
        setStudentsWithoutSchedule(list);
        setStudentsTotal(res.data?.meta?.total || list.length);
        setStudentsPage(page);
      }
    } catch (error) {
      toast.error('Không thể tải danh sách học viên');
    } finally {
      setStudentsLoading(false);
    }
  };


  const fetchLicenseCategories = async () => {
    try {
      const res = await getLicenseCategories();
      if (res.success) {
        setLicenseCategories(res.data || []);
      }
    } catch (error) {
       console.error('Failed to fetch categories', error);
    }
  };

  useEffect(() => {
    fetchExams();
    fetchEligibleStudents();
    fetchLicenseCategories();
  }, []);

  const clearFilters = () => {
    setFromDate(''); setToDate('');
    setFilterVehicle(''); setFilterStatus('');
    setSearch('');
  };

  const openCreate = () => { setEditData(null); setModalOpen(true); };
  const openEdit = (exam: any) => {
    setEditData({
      id: exam._id, 
      name: exam.name, 
      vehicleType: exam.vehicleType,
      region: exam.region, 
      plannedDate: exam.examDate ? new Date(exam.examDate).toISOString().split('T')[0] : '',
      officialDate: exam.officialDate ? new Date(exam.officialDate).toISOString().split('T')[0] : '',
      venueId: exam.stadium_id || '', // Correctly pass stadium_id
      venueName: exam.venue,
      examStatus: exam.status === 'done' ? 'completed' : exam.status, 
      note: '',
    });
    setModalOpen(true);
  };

  const handleDeleteClick = (id: string, name: string) => {
    setBatchToDelete({ id, name });
    setDeleteModalOpen(true);
  };

  const confirmDelete = async () => {
    if (!batchToDelete) return;
    try {
      await deleteExamBatch(batchToDelete.id);
      toast.success(`Đã xóa đợt thi: ${batchToDelete.name}`);
      fetchExams();
      fetchEligibleStudents(); // Refresh unscheduled list
    } catch (err) {
      toast.error('Lỗi khi xóa đợt thi');
    } finally {
      setDeleteModalOpen(false);
      setBatchToDelete(null);
    }
  };

  const handleRemoveClick = (batchId: string, studentId: string, name: string) => {
    setStudentToRemove({ id: studentId, name, batchId });
    setRemoveConfirmOpen(true);
  };

  const confirmRemoveFromBatch = async () => {
    if (!studentToRemove) return;
    try {
      // 1. Get latest batch info
      const res = await getBatchById(studentToRemove.batchId);
      if (!res.success) throw new Error('Không thể lấy thông tin đợt thi');

      const batch = res.data;
      const updatedResults = (batch.studentResults || []).filter((s: any) => s.student_id !== studentToRemove.id);

      // 2. Update backend batch
      await updateExamBatch(studentToRemove.batchId, { studentResults: updatedResults });

      // 3. Restore student status to 'Thi sát hạch'
      if (studentToRemove.id) {
        await updateStudent(studentToRemove.id, { status_detail: 'Thi sát hạch' });
      }

      toast.success(`Đã xóa ${studentToRemove.name} khỏi đợt thi`);
      fetchExams();
      fetchEligibleStudents(studentsPage); // They will reappear in unscheduled list
    } catch (err: any) {
      toast.error(err.message || 'Lỗi khi xóa học viên khỏi đợt thi');
    } finally {
      setRemoveConfirmOpen(false);
      setStudentToRemove(null);
    }
  };

  const openResultModal = (batch: any, studentRes: any) => {
    setTargetBatchForResults(batch);
    setTargetStudentForResults({
      id: studentRes.student_id,
      name: studentRes.name,
      licenseClass: batch.vehicleType === 'Xe máy' ? 'A1/A2' : 'Ô tô', // Fallback or improved mapping
      currentResult: studentRes.result,
      currentNote: studentRes.note
    });
    setResultModalOpen(true);
  };

  const handleSaveResult = async (result: string, note: string) => {
    if (!targetBatchForResults || !targetStudentForResults) return;

    try {
      // 1. Get latest batch
      const res = await getBatchById(targetBatchForResults._id);
      if (!res.success) throw new Error('Cập nhật thất bại');

      const batch = res.data;
      const updatedResults = (batch.studentResults || []).map((s: any) => {
        if (s.student_id === targetStudentForResults.id) {
          return { ...s, result, note };
        }
        return s;
      });

      // 2. Update
      await updateExamBatch(batch._id || batch.id, { studentResults: updatedResults });

      toast.success(`Đã cập nhật kết quả cho ${targetStudentForResults.name}`);
      fetchExams();
    } catch (err: any) {
      toast.error(err.message || 'Lỗi khi lưu kết quả');
    }
  };

  const displayed = (Array.isArray(exams) ? exams : []).filter(e => {
    if (filterVehicle && e.vehicleType !== filterVehicle) return false;
    if (filterStatus  && e.status !== filterStatus)   return false;
    const pDate = e.examDate ? new Date(e.examDate).toISOString().split('T')[0] : '';
    if (fromDate && pDate < fromDate)             return false;
    if (toDate   && pDate > toDate)               return false;
    if (search && typeof search === 'string') {
      const trimmedSearch = search.trim().toLowerCase();
      if (trimmedSearch && !e.name.toLowerCase().includes(trimmedSearch)) return false;
    }
    return true;
  });

  const examList = Array.isArray(exams) ? exams : [];
  const stats = [
    { icon: <Trophy className="w-5 h-5 text-indigo-600" />,  bg: 'bg-indigo-50',  label: 'Tổng đợt thi',    value: examList.length },
    { icon: <Clock className="w-5 h-5 text-amber-600" />,    bg: 'bg-amber-50',   label: 'Sắp diễn ra',     value: examList.filter(e => e.status === 'upcoming').length },
    { icon: <CheckCircle2 className="w-5 h-5 text-blue-600" />, bg: 'bg-blue-50', label: 'Đã xác nhận',     value: examList.filter(e => e.status === 'confirmed').length },
    { icon: <CheckCircle2 className="w-5 h-5 text-emerald-600" />, bg: 'bg-emerald-50', label: 'Đã hoàn thành', value: examList.filter(e => e.status === 'completed').length },
    { icon: <Users className="w-5 h-5 text-rose-500" />,     bg: 'bg-rose-50',    label: 'HV chưa có lịch', value: studentsTotal },
  ];

  return (
    <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-2 duration-700">

      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight leading-tight">Thi sát hạch</h2>
          <p className="text-gray-500 font-medium mt-1 text-sm">Quản lý đợt thi sát hạch, gắn học viên và theo dõi kết quả</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={async () => {
              try {
                setIsExporting(true);
                await exportExamBatchesToExcel();
                toast.success('Xuất Excel thành công!');
              } catch (err) {
                toast.error('Lỗi khi xuất Excel');
              } finally {
                setIsExporting(false);
              }
            }}
            disabled={isExporting}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 transition-colors shadow-sm text-sm disabled:opacity-60"
          >
            {isExporting
              ? <div className="w-4 h-4 border-2 border-gray-400 border-t-indigo-600 rounded-full animate-spin" />
              : <Download className="w-4 h-4" />}
            {isExporting ? 'Đang xuất...' : 'Xuất Excel'}
          </button>
          <button
            onClick={openCreate}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white font-bold rounded-xl shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all active:scale-95 text-sm"
          >
            <Plus className="w-4 h-4" /> Tạo đợt thi
          </button>
        </div>
      </div>

      {/* Stat cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-5 gap-3">
        {stats.map((s, i) => (
          <div key={i} className="bg-white border border-gray-100 rounded-2xl p-4 flex items-center gap-3 shadow-sm hover:shadow-md transition-shadow">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${s.bg}`}>{s.icon}</div>
            <div className="flex flex-col">
              <span className="text-xl font-black text-gray-900">{s.value}</span>
              <span className="text-[11px] font-semibold text-gray-500 leading-tight">{s.label}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1">
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'exams' ? 'bg-indigo-600 text-white shadow-md shadow-indigo-600/20' : 'text-gray-500 hover:bg-gray-100'
