          </div>

          {/* Exam list */}
          <div className="flex flex-col gap-4">
            {loading ? (
              [...Array(3)].map((_, i) => (
                <div key={i} className="bg-white border border-gray-100 rounded-2xl p-6 animate-pulse">
                  <div className="h-4 bg-gray-100 rounded w-1/4 mb-4"></div>
                  <div className="h-3 bg-gray-50 rounded w-1/2"></div>
                </div>
              ))
            ) : displayed.length === 0 ? (
              <div className="bg-white border border-gray-100 rounded-2xl p-14 flex flex-col items-center gap-3 text-gray-400 shadow-sm">
                <Trophy className="w-10 h-10 opacity-20" />
                <p className="font-semibold">Không có đợt thi nào phù hợp.</p>
              </div>
            ) : displayed.map(exam => {
              const meta   = examStatusMeta[exam.status] || examStatusMeta.upcoming;
              const isOpen = expandedId === exam._id;
              const pDate = exam.examDate ? new Date(exam.examDate).toLocaleDateString('vi-VN') : '--';
              const studentsCount = exam.studentResults?.length || 0;
              const passedCount = exam.studentResults?.filter((r: any) => r.result === 'pass').length || 0;
              const failedCount = exam.studentResults?.filter((r: any) => r.result === 'fail').length || 0;

              return (
                <div key={exam._id} className="bg-white border border-gray-100 rounded-2xl shadow-sm overflow-hidden hover:shadow-md transition-all duration-300">

                  {/* Row */}
                  <div className="px-7 py-5 flex flex-col sm:flex-row sm:items-center gap-6">

                    {/* Left info */}
                    <div className="flex-1 min-w-0 space-y-3">
                      <div className="flex flex-wrap items-center gap-3">
                        <span className="font-extrabold text-gray-900 text-lg tracking-tight">{exam.name}</span>
                        <div className="flex items-center gap-1.5">
                          <span className={`px-2 py-0.5 rounded-md text-[10px] font-black border uppercase tracking-wider ${meta.cls}`}>{meta.label}</span>
                          <span className={`px-2 py-0.5 rounded-md text-[10px] font-black border uppercase tracking-wider ${vehicleBadge(exam.vehicleType)}`}>{exam.vehicleType}</span>
                        </div>
                      </div>

                      <div className="flex flex-wrap items-center gap-5 text-[12px] text-gray-500 font-medium">
                        <div className="flex items-center gap-4">
                          <div className="flex items-center gap-1.5">
                            <CalendarDays className="w-3.5 h-3.5 text-gray-300" />
                            <span>Dự kiến: <strong className="text-gray-700 ml-0.5 font-bold">{pDate}</strong></span>
                          </div>
                          <div className="w-px h-3 bg-gray-100" />
                          <div className="flex items-center gap-1.5">
                            <CalendarDays className="w-3.5 h-3.5 text-indigo-300" />
                            <span>Chính thức: <strong className="text-indigo-600 ml-0.5 font-black">{exam.officialDate ? new Date(exam.officialDate).toLocaleDateString('vi-VN') : '—'}</strong></span>
                          </div>
                        </div>

                        <div className="flex items-center gap-1.5">
                          <MapPin className="w-3.5 h-3.5 text-gray-300" />
                          <span className="font-bold text-gray-600">{exam.venue}</span>
                        </div>
                      </div>
                    </div>

                    {/* Right stats + actions */}
                    <div className="flex items-center gap-6 shrink-0">
                      {/* Student counts */}
                      <div className="flex items-center gap-4 text-center px-4 py-2 bg-gray-50/50 rounded-2xl border border-gray-50">
                        <div className="flex flex-col">
                          <span className="text-lg font-black text-gray-800 leading-none">{studentsCount}</span>
                          <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">Học viên</span>
                        </div>
                        <div className="flex flex-col border-l border-gray-100 pl-4">
                          <span className="text-lg font-black text-emerald-600 leading-none">{passedCount}</span>
                          <span className="text-[9px] font-bold text-emerald-400 uppercase tracking-widest mt-1">Đậu</span>
                        </div>
                        <div className="flex flex-col border-l border-gray-100 pl-4">
                          <span className="text-lg font-black text-rose-500 leading-none">{failedCount}</span>
                          <span className="text-[9px] font-bold text-rose-400 uppercase tracking-widest mt-1">Trượt</span>
                        </div>
                      </div>

                      {/* Action buttons */}
                      <div className="flex items-center gap-1 pl-4 border-l border-gray-100">
                        <button onClick={() => openEdit(exam)}
                          title="Sửa đợt thi"
                          className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all active:scale-95">
                          <Edit2 className="w-4.5 h-4.5" />
                        </button>
                        <button 
                          onClick={() => handleDeleteClick(exam._id, exam.name)}
                          title="Xóa đợt thi"
                          className="p-2 text-gray-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all active:scale-95"
                        >
                          <Trash2 className="w-4.5 h-4.5" />
                        </button>
                        <button onClick={() => setExpandedId(isOpen ? null : exam._id)}
                          title="Mở rộng"
                          className={`p-2 rounded-xl transition-all active:scale-95 ${isOpen ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-700'}`}>
                          {isOpen ? <ChevronUp className="w-4.5 h-4.5" /> : <ChevronDown className="w-4.5 h-4.5" />}
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Expanded panel */}
                  {isOpen && (
                    <div className="border-t border-gray-100 bg-gray-50/50 px-5 py-4 animate-in slide-in-from-top-2 duration-200">
                      <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Học viên trong đợt thi</p>
                      {studentsCount === 0 ? (
                        <div className="flex items-center gap-2 text-gray-400 font-medium text-sm py-4">
                          <AlertCircle className="w-4 h-4" /> Chưa có học viên nào được gắn vào đợt thi này.
                        </div>
                      ) : (
                        <div className="flex flex-col gap-2">
                          {exam.studentResults.map((result: any, i: number) => (
                            <div key={i} className="flex items-center justify-between bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm group/item">
                              <div className="flex items-center gap-3">
                                <span className="w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center text-[11px] font-black group-hover/item:bg-indigo-600 group-hover/item:text-white transition-all">
                                  {i + 1}
                                </span>
                                <div className="flex flex-col">
                                  <span 
                                    className="font-extrabold text-gray-700 hover:text-indigo-600 cursor-pointer transition-colors"
                                    onClick={() => setSelectedStudent({ _id: result.student_id, user_id: { first_name: result.name } })}
                                  >
                                    {result.name || `Học viên #${i + 1}`}
                                  </span>
                                  <span className="text-gray-400 text-[10px] font-medium">{result.student_id ? `Mã HV: ${result.student_id.slice(-6).toUpperCase()}` : '—'}</span>
                                </div>
                              </div>

                              <div className="flex items-center gap-3">
                                <span className={`text-[10px] font-bold px-2 py-1 rounded border transition-all ${
                                  result.result === 'pass' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                                  result.result === 'fail' ? 'bg-rose-50 text-rose-600 border-rose-100' : 
                                  'bg-gray-50 text-gray-400 border-gray-200'
                                }`}>
                                  {result.result === 'pass' ? 'Đã đậu' : result.result === 'fail' ? 'Trượt' : 'Chờ kết quả'}
                                </span>

                                <div className="flex items-center gap-1 opacity-0 group-hover/item:opacity-100 transition-opacity">
                                  <button
                                    onClick={() => openResultModal(exam, result)}
                                    title="Nhập kết quả"
                                    className="p-1.5 text-indigo-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                  >
                                    <ClipboardCheck className="w-4 h-4" />
                                  </button>
                                  <button
                                    onClick={() => handleRemoveClick(exam._id, result.student_id, result.name)}
                                    title="Xóa khỏi đợt thi"
                                    className="p-1.5 text-gray-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
                                  >
                                    <UserMinus className="w-4 h-4" />
                                  </button>
                                </div>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </>
      )}

      {/* ── TAB: HV chưa có lịch ── */}
      {activeTab === 'no-schedule' && (
        <div className="bg-white border border-gray-100 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-gray-100 flex items-center justify-between">
            <h3 className="font-extrabold text-gray-800">Học viên chưa được xếp lịch thi</h3>
            <div className="relative">
              <Search className="w-4 h-4 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
              <input type="text" value={search} onChange={e => setSearch(e.target.value)}
                placeholder="Tìm tên, SĐT..."
                className="pl-9 pr-4 py-1.5 text-sm bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/20 w-48 transition-all" />
            </div>
          </div>
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50/60 border-b border-gray-100 text-[11px] uppercase tracking-wider text-gray-500 font-extrabold">
                <th className="px-6 py-3">Học viên</th>
                <th className="px-6 py-3">Hạng</th>
                <th className="px-6 py-3 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50 text-sm">
              {studentsLoading ? (
                <tr>
                  <td colSpan={3} className="px-6 py-10 text-center text-gray-400">Đang tải danh sách học viên...</td>
                </tr>
              ) : studentsWithoutSchedule.length === 0 ? (
                <tr>
                  <td colSpan={3} className="px-6 py-10 text-center text-gray-400 italic">Không có học viên nào đang chờ lịch thi sát hạch.</td>
                </tr>
              ) : studentsWithoutSchedule
                .filter(s => {
                  // FILTER: Exclude students already assigned to an active exam batch
                  const isAssigned = exams.some(exam => 
                    (exam.status === 'upcoming' || exam.status === 'confirmed') && 
                    (exam.studentResults || []).some((sr: any) => sr.student_id === s._id)
                  );
                  if (isAssigned) return false;

                  const fullName = `${s.user_id?.last_name || ''} ${s.user_id?.first_name || ''}`.toLowerCase();
                  return !search || fullName.includes(search.toLowerCase()) || s.user_id?.phone?.includes(search);
                })
                .map(s => {
                  const firstName = s.user_id?.first_name || '';
                  const lastName = s.user_id?.last_name || '';
                  const fullName = firstName || lastName ? `${lastName} ${firstName}`.trim() : 'Học viên ẩn danh';
                  const phone = s.user_id?.phone || '—';
                  const region = s.region_id?.name || '—';

                  return (
                    <tr key={s._id} className="hover:bg-indigo-50/20 transition-colors">
                      <td className="px-6 py-4">
                        <div
                          className="flex flex-col cursor-pointer group"
                          onClick={() => setSelectedStudent(s)}
                        >
                          <span className="font-extrabold text-indigo-700 transition-colors group-hover:text-indigo-900">
                            {fullName}
                          </span>
                          <span className="text-[11px] text-gray-400 group-hover:text-gray-500">{phone}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="px-1.5 py-0.5 bg-blue-50 text-blue-700 text-[10px] font-black border border-blue-100 rounded">{s.license_category_id || '—'}</span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => setAssignStudent({
                            id: s._id,
                            name: fullName
                          })}
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-indigo-600 text-white hover:bg-indigo-700 transition-colors rounded-lg font-bold text-xs shadow-sm shadow-indigo-600/20"
                        >
                          <Plus className="w-3.5 h-3.5" /> Gắn vào đợt thi
                        </button>
                      </td>
                    </tr>
                  );
                })}
            </tbody>
          </table>

          {/* Pagination Controls */}
          {studentsTotal > STUDENT_LIMIT && (
            <div className="px-6 py-4 bg-gray-50/50 border-t border-gray-100 flex items-center justify-between">
              <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">
                Trang {studentsPage} / {Math.ceil(studentsTotal / STUDENT_LIMIT)}
              </span>
              <div className="flex items-center gap-2">
                <button
                  disabled={studentsPage <= 1}
                  onClick={() => fetchEligibleStudents(studentsPage - 1)}
                  className="px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-xs font-black text-gray-700 hover:bg-gray-50 disabled:opacity-40 transition-colors uppercase"
                >
                  Trước
                </button>
                <div className="flex items-center gap-1">
                   {[...Array(Math.min(5, Math.ceil(studentsTotal / STUDENT_LIMIT)))].map((_, i) => {
                     const pNum = i + 1; // Simplistic pagination for now
                     return (
                       <button
                         key={pNum}
                         onClick={() => fetchEligibleStudents(pNum)}
                         className={`w-8 h-8 rounded-lg text-xs font-black transition-all ${
                           studentsPage === pNum ? 'bg-rose-500 text-white shadow-md shadow-rose-500/20' : 'text-gray-500 hover:bg-gray-100'
                         }`}
                       >
                         {pNum}
                       </button>
                     );
                   })}
                </div>
                <button
                  disabled={studentsPage >= Math.ceil(studentsTotal / STUDENT_LIMIT)}
                  onClick={() => fetchEligibleStudents(studentsPage + 1)}
                  className="px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-xs font-black text-gray-700 hover:bg-gray-50 disabled:opacity-40 transition-colors uppercase"
                >
                  Sau
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Modal */}
      <ExamModal 
        isOpen={modalOpen} 
        onClose={() => setModalOpen(false)} 
        onSuccess={() => fetchExams()}
        initial={editData} 
      />

      {/* Student Detail Drawer */}
      <StudentDetailDrawer
        isOpen={!!selectedStudent}
        student={mapStudentForDrawer(selectedStudent)}
        onClose={() => setSelectedStudent(null)}
      />

      {/* Assign to exam modal */}
      <AssignExamModal
        isOpen={!!assignStudent}
        student={assignStudent}
        onClose={() => setAssignStudent(null)}
        onSuccess={() => {
          fetchExams();
          fetchEligibleStudents();
        }}
      />
      {/* Result Entry Modal */}
      <ResultModal
        isOpen={resultModalOpen}
        onClose={() => { setResultModalOpen(false); setTargetStudentForResults(null); }}
        onSave={handleSaveResult}
        student={targetStudentForResults}
        examBatch={targetBatchForResults}
      />

      {/* Remove from Batch Confirmation */}
      <ConfirmModal
        isOpen={removeConfirmOpen}
        onClose={() => setRemoveConfirmOpen(false)}
        onConfirm={confirmRemoveFromBatch}
        title="Xóa khỏi đợt thi"
        message={`Bạn có chắc chắn muốn gỡ học viên "${studentToRemove?.name}" khỏi đợt thi này? Học viên sẽ quay lại danh sách chờ xếp lịch.`}
        confirmText="Xác nhận gỡ"
        cancelText="Quay lại"
        type="warning"
      />

      {/* Confirm Delete Batch */}
      <ConfirmModal
        isOpen={deleteModalOpen}
        onClose={() => setDeleteModalOpen(false)}
        onConfirm={confirmDelete}
        title="Xóa đợt thi"
        message={`Bạn có chắc chắn muốn xóa đợt thi "${batchToDelete?.name}"? Hành động này không thể hoàn tác.`}
        confirmText="Xác nhận xóa"
        cancelText="Quay lại"
        type="danger"
      />
    </div>
  );
}

