edits.newText:
export const exportExamBatchesToExcel = async (filters: Record<string, string> = {}) => {
  const params = new URLSearchParams(filters).toString();
  const endpoint = `/exam-batches/export${params ? '?' + params : ''}`;

  const blob = await apiClient(endpoint, { responseType: 'blob' });

  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `danh_sach_dot_thi_sat_hach_${new Date().toISOString().split('T')[0]}.xlsx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

export const importExamResults = async (batchId: string, file: File) => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('batchId', batchId);
  const token = typeof window !== 'undefined' ? localStorage.getItem('accessToken') : '';
  const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/v1/exam-batches/${batchId}/import-results`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}` },
    body: formData,
  });
  return response.json();
};

export const getBatchStats = async (batchId: string) => {
  const token = typeof window !== 'undefined' ? localStorage.getItem('accessToken') : '';
  const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/v1/exam-batches/${batchId}/stats`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  return response.json();
};

