"use client";

import React, { useState, useEffect } from 'react';
import { X, Trophy, AlertCircle, HelpCircle, Save, Loader2, BookOpen } from 'lucide-react';

interface ResultModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: { result: string; theory_result?: string; simulation_result?: string; parking_result?: string; road_result?: string; note: string }) => Promise<void>;
  student: {
    id: string;
    name: string;
    licenseClass: string;
    currentResult?: string;
    currentNote?: string;
    theoryResult?: string;
    simulationResult?: string;
    parkingResult?: string;
    roadResult?: string;
  } | null;
  examBatch: { name: string; officialDate: string | null } | null;
}

export default function ResultModal({ isOpen, onClose, onSave, student, examBatch }: ResultModalProps) {
  const [result, setResult] = useState('no_result');
  const [note, setNote] = useState('');
  const [theoryResult, setTheoryResult] = useState('no_result');
  const [simulationResult, setSimulationResult] = useState('no_result');
  const [parkingResult, setParkingResult] = useState('no_result');
  const [roadResult, setRoadResult] = useState('no_result');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validate = (r: string, n: string) => {
    const errs: Record<string, string> = {};
    if (r === 'fail' && !n.trim()) {
      errs.note = "Vui lòng nhập lý do nếu kết quả là 'Trượt'";
    }
    return errs;
  };

  useEffect(() => {
    if (isOpen && student) {
      setResult(student.currentResult || 'no_result');
      setNote(student.currentNote || '');
      setTheoryResult(student.theoryResult || 'no_result');
      setSimulationResult(student.simulationResult || 'no_result');
      setParkingResult(student.parkingResult || 'no_result');
      setRoadResult(student.roadResult || 'no_result');
      setTouched({});
      setErrors({});
    }
  }, [isOpen, student]);

  const touch = (field: string) => {
    setTouched(prev => ({ ...prev, [field]: true }));
    setErrors(validate(result, note));
  };

  const updateResult = (val: string) => {
    setResult(val);
    setErrors(validate(val, note));
  };

  const updateNote = (val: string) => {
    setNote(val);
    setErrors(validate(result, val));
  };

  if (!isOpen || !student || !examBatch) return null;

  const handleSave = async () => {
    const errs = validate(result, note);
    setErrors(errs);
    setTouched({ result: true, note: true });

    if (Object.keys(errs).length > 0) return;

    try {
      setIsSubmitting(true);
      await onSave({
        result,
        theory_result: theoryResult === 'no_result' ? undefined : theoryResult,
        simulation_result: simulationResult === 'no_result' ? undefined : simulationResult,
        parking_result: parkingResult === 'no_result' ? undefined : parkingResult,
        road_result: roadResult === 'no_result' ? undefined : roadResult,
        note
      });
      onClose();
    } catch (err: any) {
      if (err.response?.data?.errors) {
        const serverErrs: any = {};
        err.response.data.errors.forEach((e: any) => {
          const path = e.path.split('.').pop();
          serverErrs[path] = e.message;
        });
        setErrors(prev => ({ ...prev, ...serverErrs }));
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const FieldWrapper = ({ label, children, field }: { label: string, children: React.ReactNode, field: string }) => (
    <div className="flex flex-col gap-2">
      <label className={`text-[11px] font-black uppercase tracking-widest ml-1 transition-colors ${touched[field] && errors[field] ? 'text-rose-500' : 'text-gray-400'}`}>
        {label}
      </label>
      <div className="relative group">
        {children}
      </div>
      {touched[field] && errors[field] && (
        <p className="text-[10px] font-bold text-rose-500 ml-1 mt-0.5 animate-in fade-in slide-in-from-top-1">
          {errors[field]}
        </p>
      )}
    </div>
  );

  const results = [
    { value: 'no_result', label: 'Chờ kết quả', icon: <HelpCircle className="w-4 h-4" />, cls: 'bg-gray-50 text-gray-600 border-gray-200' },
    { value: 'pass', label: 'Đạt', icon: <Trophy className="w-4 h-4" />, cls: 'bg-emerald-50 text-emerald-600 border-emerald-100' },
    { value: 'fail', label: 'Trượt', icon: <AlertCircle className="w-4 h-4" />, cls: 'bg-rose-50 text-rose-600 border-rose-100' },
  ];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-[2rem] w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200 overflow-hidden border border-gray-100">

        {/* Header */}
        <div className="px-8 py-6 border-b border-gray-100 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-black text-gray-900 tracking-tight">Nhập kết quả thi</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-sm font-bold text-gray-500">{student.name}</span>
              <span className="w-1 h-1 rounded-full bg-gray-300"></span>
              <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[10px] font-black uppercase border border-indigo-100">
                {student.licenseClass}
              </span>
            </div>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-gray-900 hover:bg-gray-100 rounded-xl transition-all">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Body */}
        <div className="p-8 flex flex-col gap-6">

          {/* Exam Context */}
          <div className="p-4 bg-gray-50/80 border border-gray-100 rounded-2xl flex items-start gap-3">
             <div className="w-8 h-8 rounded-lg bg-white shadow-sm flex items-center justify-center shrink-0">
                <BookOpen className="w-4 h-4 text-indigo-500" />
             </div>
             <div className="flex flex-col">
                <span className="text-[13px] font-bold text-gray-700">{examBatch.name}</span>
                <span className="text-[11px] text-gray-400 font-medium">
                  Chính thức: {examBatch.officialDate ? new Date(examBatch.officialDate).toLocaleDateString('vi-VN') : 'Chưa cập nhật'}
                </span>
             </div>
          </div>

          {/* Result Select */}
          <FieldWrapper label="KẾT QUẢ TỔNG" field="result">
              <select
                value={result}
                onChange={(e) => updateResult(e.target.value)}
                onBlur={() => touch('result')}
                className={`w-full px-5 py-4 bg-gray-50 border rounded-2xl text-sm font-black tracking-tight focus:outline-none focus:ring-4 transition-all cursor-pointer appearance-none ${
                    touched.result && errors.result 
                    ? 'border-rose-300 bg-rose-50 focus:ring-rose-500/10 focus:border-rose-500 text-rose-900' 
                    : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
                }`}
              >
                {results.map((r) => (
                  <option key={r.value} value={r.value}>{r.label}</option>
                ))}
              </select>
              <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                <HelpCircle className="w-4 h-4" />
              </div>
          </FieldWrapper>

          {/* Sub-section Results */}
          <div className="grid grid-cols-2 gap-3">
            <FieldWrapper label="LÝ THUYẾT" field="theory">
              <select value={theoryResult} onChange={e => setTheoryResult(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/10 cursor-pointer appearance-none">
                <option value="no_result">Chưa có</option>
                <option value="pass">Đạt</option>
                <option value="fail">Trượt</option>
                <option value="absent">Vắng</option>
              </select>
            </FieldWrapper>
            <FieldWrapper label="MÔ PHỎNG" field="simulation">
              <select value={simulationResult} onChange={e => setSimulationResult(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/10 cursor-pointer appearance-none">
                <option value="no_result">Chưa có</option>
                <option value="pass">Đạt</option>
                <option value="fail">Trượt</option>
                <option value="absent">Vắng</option>
              </select>
            </FieldWrapper>
            <FieldWrapper label="SA HÌNH" field="parking">
              <select value={parkingResult} onChange={e => setParkingResult(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/10 cursor-pointer appearance-none">
                <option value="no_result">Chưa có</option>
                <option value="pass">Đạt</option>
                <option value="fail">Trượt</option>
                <option value="absent">Vắng</option>
              </select>
            </FieldWrapper>
            <FieldWrapper label="ĐƯỜNG TRƯỜNG" field="road">
              <select value={roadResult} onChange={e => setRoadResult(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/10 cursor-pointer appearance-none">
                <option value="no_result">Chưa có</option>
                <option value="pass">Đạt</option>
                <option value="fail">Trượt</option>
                <option value="absent">Vắng</option>
              </select>
            </FieldWrapper>
          </div>

          {/* Note Input */}
          <FieldWrapper label="GHI CHÚ" field="note">
            <textarea
              value={note}
              onChange={(e) => updateNote(e.target.value)}
              onBlur={() => touch('note')}
              placeholder="Ghi chú thêm..."
              rows={3}
              className={`w-full px-5 py-4 bg-gray-50 border rounded-2xl text-sm font-medium focus:outline-none focus:ring-4 transition-all resize-none ${
                  touched.note && errors.note 
                  ? 'border-rose-300 bg-rose-50 focus:ring-rose-500/10 focus:border-rose-500 text-rose-900' 
                  : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
              }`}
            />
          </FieldWrapper>
        </div>

        {/* Footer */}
        <div className="px-8 py-6 border-t border-gray-100 bg-gray-50/50 flex items-center justify-end gap-3">
          <button
            onClick={onClose}
            className="px-6 py-3 text-sm font-black text-gray-500 hover:text-gray-900 transition-colors uppercase tracking-widest text-[11px]"
          >
            Hủy
          </button>
          <button
            onClick={handleSave}
            disabled={isSubmitting}
            className="flex items-center gap-2 px-8 py-3.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-600/20 transition-all hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-widest text-[11px]"
          >
            {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
            Lưu kết quả
          </button>
        </div>

      </div>
    </div>
  );
}

