        isOpen={deleteModalOpen}
        onClose={() => setDeleteModalOpen(false)}
        onConfirm={confirmDelete}
        title="Xóa đợt thi"
        message={`Bạn có chắc chắn muốn xóa đợt thi "${batchToDelete?.name}"? Hành động này không thể hoàn tác.`}
        confirmText="Xác nhận xóa"
        cancelText="Quay lại"
        type="danger"
      />
    </div>
  );
}

